section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/go-error-handling",
  "type": "object",
  "required": ["apperrorPackage", "middlewareOrder", "lintConfig"],
  "properties": {
    "apperrorPackage": {
      "type": "object",
      "required": ["type", "constructors", "wrap"],
      "properties": {
        "type": {"const": "AppError"},
        "constructors": {"type": "array", "items": {"type": "string"}, "minItems": 3},
        "wrap": {"const": "Wrap(err error, msg string) *AppError"}
      }
    },
    "middlewareOrder": {
      "type": "array",
      "description": "Recovery FIRST, then ErrorMapper.",
      "items": {"enum": ["RequestID", "Recovery", "Logger", "ErrorMapper", "Auth", "..."]}
    },
    "lintConfig": {
      "type": "object",
      "required": ["enabled"],
      "properties": {
        "enabled": {
          "type": "array",
          "items": {"enum": ["errorlint", "wrapcheck", "errcheck", "nilnil"]},
          "minItems": 4
        }
      }
    }
  }
}

example.code:
// pkg/apperror/apperror.go
type AppError struct {
    Code       string
    Message    string
    HTTPStatus int
    Err        error
}
func (e *AppError) Error() string { return e.Message }
func (e *AppError) Unwrap() error  { return e.Err }
func NewNotFound(name string) *AppError {
    return &AppError{Code: "not_found", Message: name + " not found", HTTPStatus: 404}
}
func Wrap(err error, msg string) *AppError {
    var ae *AppError
    if errors.As(err, &ae) {
        return &AppError{Code: ae.Code, Message: msg + ": " + ae.Message,
                          HTTPStatus: ae.HTTPStatus, Err: err}  // r9: preserve status
    }
    return &AppError{Code: "internal", Message: msg, HTTPStatus: 500, Err: err}
}

// internal/repository/user.go
func (r *userRepo) Get(ctx context.Context, id string) (*model.User, error) {
    var u model.User
    err := r.db.QueryRow(ctx, "...").Scan(...)
    if errors.Is(err, pgx.ErrNoRows) {
        return nil, apperror.NewNotFound("user")        // r3: boundary mapping
    }
    if err != nil {
        return nil, fmt.Errorf("user repo get %s: %w", id, err)  // r2: %w
    }
    return &u, nil
}

// REJECTED — multiple violations
var ErrNotFound = &AppError{Message: "not found", HTTPStatus: 404}   // r8 mutable global

func (r *userRepo) Get(id string) (*model.User, error) {
    err := r.db.QueryRow(...).Scan(...)
    if err == sql.ErrNoRows {                            // type assert, r2
        return nil, fmt.Errorf("user not found: %v", err) // %v strips chain, r2
    }
    return nil, err                                       // driver error leaks (r3)
}

func handler(c *gin.Context) {
    u, err := repo.Get(c.Param("id"))
    if ae, ok := err.(*AppError); ok {                    // type assertion, r2
        c.JSON(500, ae)                                   // status demotion, r9
    }
}
